INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(44, 'The manager insisted ___ seeing the report before the meeting.', ARRAY['on','in','at','for'], 'on', '''Insist on'' is the correct phrasal verb. We say "insist on doing something".', 'Which preposition follows "insist"?', 'Preposition'),
(44, 'If I ___ rich, I would travel the world.', ARRAY['am','was','were','be'], 'were', 'In second conditional (unreal present), we use "were" for all subjects, including "I".', 'Unreal present condition.', 'Conditional'),
(44, 'The book ___ by millions of readers every year.', ARRAY['reads','is read','has read','reading'], 'is read', 'Passive voice in simple present: subject + is/are + past participle.', 'Who performs the action?', 'Passive Voice'),
(44, 'She asked me where I ___.', ARRAY['live','lived','do live','am live'], 'lived', 'In reported speech, the present tense shifts to past tense. "Where do you live?" becomes "where I lived".', 'Reported speech tense shift.', 'Reported Speech'),
(44, 'The woman ___ called you is my aunt.', ARRAY['who','whom','whose','which'], 'who', '''Who'' is used as a subject relative pronoun for people. The woman performed the action of calling.', 'Subject or object of the clause?', 'Relative Clause');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(45, 'She is not accustomed ___ waking up early.', ARRAY['to','of','for','with'], 'to', '''Accustomed to'' is the correct collocation meaning "used to something".', 'What follows "accustomed"?', 'Preposition'),
(45, '___ Eiffel Tower is in Paris.', ARRAY['A','An','The','No article'], 'The', 'We use "The" before names of famous monuments and landmarks.', 'Is it a unique landmark?', 'Article'),
(45, 'By the time we arrive, the show ___.', ARRAY['will start','will have started','starts','started'], 'will have started', 'Future perfect is used when one future action will be completed before another future action.', 'Which action happens first?', 'Tense'),
(45, 'You ___ see a doctor about that cough.', ARRAY['should','would','could','might'], 'should', '''Should'' is used to give advice or recommendations.', 'Giving advice.', 'Modal Verb'),
(45, 'He speaks ___ fluently that everyone thinks he is a native speaker.', ARRAY['such','too','so','very'], 'so', '''So...that'' is used to show cause and effect with adverbs and adjectives.', 'Cause and effect with an adverb.', 'Adjective/Adverb');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(46, 'If she had studied harder, she ___ the exam.', ARRAY['would pass','would have passed','will pass','passed'], 'would have passed', 'Third conditional (unreal past): If + had + past participle, would have + past participle.', 'Is this about an unreal past?', 'Conditional'),
(46, 'The letter ___ yesterday.', ARRAY['was sent','sent','is sent','has sent'], 'was sent', 'Passive voice in simple past: subject + was/were + past participle.', 'Focus on the receiver of the action.', 'Passive Voice'),
(46, 'He told me that he ___ the next day.', ARRAY['will come','would come','comes','is coming'], 'would come', 'In reported speech, "will" changes to "would" and "tomorrow" changes to "the next day".', 'Reported speech modal shift.', 'Reported Speech'),
(46, 'The house ___ roof was damaged has been repaired.', ARRAY['who','which','whose','that'], 'whose', '''Whose'' is used to show possession in relative clauses. The roof belongs to the house.', 'Possession in a relative clause.', 'Relative Clause'),
(46, 'Neither the teacher ___ the students were aware of the change.', ARRAY['or','and','nor','but'], 'nor', '''Neither...nor'' is a correlative conjunction pair used to negate two items.', 'What pairs with "neither"?', 'Conjunction');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(47, 'They are thinking ___ moving to a new city.', ARRAY['about','of','for','on'], 'about', '''Thinking about'' means considering or contemplating something.', 'Which preposition follows "thinking"?', 'Preposition'),
(47, 'Each student ___ required to submit the assignment on time.', ARRAY['is','are','were','have been'], 'is', '''Each'' is always singular and takes a singular verb.', '"Each" is singular or plural?', 'Subject-Verb Agreement'),
(47, '___ I borrow your pen for a moment?', ARRAY['May','Should','Must','Will'], 'May', '''May'' is used to ask for permission politely.', 'Asking for permission.', 'Modal Verb'),
(47, 'She danced ___ gracefully at the event.', ARRAY['much','very','too','enough'], 'very', '''Very'' modifies adverbs to intensify them. "Very gracefully" means extremely gracefully.', 'Intensifying an adverb.', 'Adjective/Adverb'),
(47, 'The students wondered ___ the results would be announced.', ARRAY['that','if','what','which'], 'if', 'In reported yes/no questions, we use "if" or "whether" to introduce the clause.', 'Reported yes/no question.', 'Reported Speech');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(48, 'He congratulated her ___ winning the award.', ARRAY['for','on','about','with'], 'on', '''Congratulate someone on'' is the correct collocation.', 'Which preposition goes with "congratulate"?', 'Preposition'),
(48, 'If it rains tomorrow, we ___ stay indoors.', ARRAY['will','would','could','shall'], 'will', 'First conditional (real possibility): If + present simple, will + base verb.', 'Is this a real or unreal condition?', 'Conditional'),
(48, 'A new hospital ___ in our town right now.', ARRAY['is building','is being built','has built','builds'], 'is being built', 'Present continuous passive: subject + is/are + being + past participle.', 'Is the hospital doing the building?', 'Passive Voice'),
(48, 'The boy ___ you met at the party is my cousin.', ARRAY['who','whom','whose','which'], 'whom', '''Whom'' is used as the object of the relative clause. "You met" the boy (object).', 'Is the person subject or object?', 'Relative Clause'),
(48, 'She finished her work ___ she could leave early.', ARRAY['so that','because','although','unless'], 'so that', '''So that'' expresses purpose — the reason she finished her work.', 'Purpose or cause?', 'Conjunction');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(49, 'We are looking ___ a new apartment.', ARRAY['at','for','into','after'], 'for', '''Looking for'' means searching for something.', 'Searching vs. investigating.', 'Preposition'),
(49, '___ Amazon is the longest river in South America.', ARRAY['A','An','The','No article'], 'The', 'We use "The" before names of rivers.', 'Article rule for rivers.', 'Article'),
(49, 'She ___ dinner when the phone rang.', ARRAY['cooked','was cooking','has cooked','cooks'], 'was cooking', 'Past continuous is used for an action in progress when interrupted by another past action.', 'Interrupted ongoing action.', 'Tense'),
(49, 'This is the park ___ we used to play as children.', ARRAY['which','that','where','when'], 'where', '''Where'' is used as a relative adverb for places.', 'Referring to a place.', 'Relative Clause'),
(49, '___ he was tired, he continued working until midnight.', ARRAY['Although','Because','So','Unless'], 'Although', '''Although'' introduces a contrast — he was tired but still continued working.', 'Contrast or cause?', 'Conjunction');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(50, 'She has been recovering ___ her illness for two weeks.', ARRAY['from','of','with','by'], 'from', '''Recover from'' is the correct collocation for illnesses.', 'Which preposition follows "recover"?', 'Preposition'),
(50, 'The teacher said that the earth ___ round.', ARRAY['is','was','has been','had been'], 'is', 'Universal truths remain in the present tense even in reported speech.', 'Is this a universal truth?', 'Reported Speech'),
(50, '___ the children ___ the mother was ready to leave.', ARRAY['Neither...nor','Either...or','Both...and','Not only...but also'], 'Neither...nor', '''Neither...nor'' negates both items — nobody was ready to leave.', 'Negating two items.', 'Conjunction'),
(50, 'He could not decide ___ to accept the offer.', ARRAY['if','that','what','whether'], 'whether', '''Whether'' is used before "to + infinitive" to express doubt between options.', 'Doubt between two options.', 'Pronoun'),
(50, 'You ___ have told me earlier about the meeting.', ARRAY['should','would','could','might'], 'should', '''Should have + past participle'' expresses regret or criticism about a past action.', 'Criticism about the past.', 'Modal Verb');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(51, 'He disposed ___ the old furniture last week.', ARRAY['of','off','away','out'], 'of', '''Dispose of'' means to get rid of something.', 'Which preposition follows "dispose"?', 'Preposition'),
(51, 'If I ___ you, I would apologize immediately.', ARRAY['am','was','were','be'], 'were', 'Second conditional uses "were" for all subjects in the if-clause.', 'Giving hypothetical advice.', 'Conditional'),
(51, 'The results ___ announced next Monday.', ARRAY['will be','will have','are being','have been'], 'will be', 'Future simple passive: subject + will be + past participle.', 'Future passive construction.', 'Passive Voice'),
(51, 'Everybody ___ excited about the upcoming trip.', ARRAY['is','are','were','have been'], 'is', '''Everybody'' is an indefinite pronoun that takes a singular verb.', '"Everybody" — singular or plural?', 'Subject-Verb Agreement'),
(51, 'She works ___ hard that she rarely takes a break.', ARRAY['such','very','so','too'], 'so', '''So...that'' is used with adjectives and adverbs to express result.', 'Result clause with an adverb.', 'Adjective/Adverb');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(52, 'The manager approved ___ the new budget plan.', ARRAY['of','for','to','at'], 'of', '''Approve of'' means to have a favorable opinion. Note: "approve" alone means to officially accept.', 'Favorable opinion vs. official acceptance.', 'Preposition'),
(52, '___ Mount Kilimanjaro is in Tanzania.', ARRAY['A','An','The','No article'], 'No article', 'No article is used before the names of individual mountains.', 'Mountains: article or no article?', 'Article'),
(52, 'They ___ in this city since they were children.', ARRAY['live','lived','have lived','are living'], 'have lived', 'Present perfect is used with "since" to show an action that started in the past and continues.', '"Since" requires which tense?', 'Tense'),
(52, 'The car ___ was parked outside belongs to my neighbor.', ARRAY['who','whom','which','whose'], 'which', '''Which'' is used as a relative pronoun for things and animals.', 'Referring to a thing.', 'Relative Clause'),
(52, 'She asked him ___ he had finished the project.', ARRAY['that','if','what','which'], 'if', 'Reported yes/no questions use "if" or "whether" instead of "that".', 'Reported yes/no question.', 'Reported Speech');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(53, 'She takes pride ___ her achievements.', ARRAY['in','on','of','for'], 'in', '''Take pride in'' is the correct collocation.', 'Which preposition goes with "take pride"?', 'Preposition'),
(53, 'If they had left earlier, they ___ the train.', ARRAY['will catch','would catch','would have caught','had caught'], 'would have caught', 'Third conditional: If + had + past participle, would have + past participle. An unreal past situation.', 'Can the past be changed?', 'Conditional'),
(53, 'He ___ to finish the report by Friday.', ARRAY['must','has','need','ought'], 'ought', '''Ought to'' expresses obligation or expectation, similar to "should".', 'A mild obligation.', 'Modal Verb'),
(53, '___ he ___ she wanted to go first, so they went together.', ARRAY['Neither...nor','Either...or','Both...and','Not only...but also'], 'Neither...nor', '''Neither...nor'' means not one and not the other. Neither wanted to go first.', 'Double negation with two subjects.', 'Conjunction'),
(53, 'He runs ___ fast as his brother.', ARRAY['so','as','more','too'], 'as', '''As...as'' is used to compare two things that are equal. "As fast as" shows equal speed.', 'Equal comparison.', 'Adjective/Adverb');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(54, 'The children were prohibited ___ playing near the construction site.', ARRAY['from','of','to','for'], 'from', '''Prohibit from'' is the correct collocation meaning to forbid.', 'Which preposition follows "prohibit"?', 'Preposition'),
(54, 'Many valuable paintings ___ during the war.', ARRAY['destroyed','were destroyed','have destroyed','are destroying'], 'were destroyed', 'Past simple passive: subject + was/were + past participle.', 'Focus on the object, not the agent.', 'Passive Voice'),
(54, 'The teacher told the students ___ they must study harder.', ARRAY['what','that','if','whether'], 'that', '''That'' introduces a reported statement (not a question).', 'Reported statement.', 'Reported Speech'),
(54, 'This is the reason ___ I was late.', ARRAY['which','that','why','where'], 'why', '''Why'' is used as a relative adverb for reasons.', 'Referring to a reason.', 'Relative Clause'),
(54, 'He picked up the phone ___ answered politely.', ARRAY['but','or','and','so'], 'and', '''And'' joins two sequential actions performed by the same subject.', 'Connecting sequential actions.', 'Conjunction');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(55, 'She is engaged ___ a well-known businessman.', ARRAY['to','with','by','for'], 'to', '''Engaged to'' is the correct collocation when talking about marriage.', 'Which preposition follows "engaged" (marriage)?', 'Preposition'),
(55, '___ honest person is respected everywhere.', ARRAY['A','An','The','No article'], 'An', '''Honest'' starts with a silent ''h'', so we use "An" before it.', 'Listen to the first sound, not the letter.', 'Article'),
(55, 'She ___ three novels by the end of this year.', ARRAY['writes','will write','will have written','has written'], 'will have written', 'Future perfect: will have + past participle, for an action completed by a future point.', 'Completed before a future time.', 'Tense'),
(55, '___ of the students has submitted the form yet.', ARRAY['None','All','Some','Many'], 'None', '''None of'' + plural noun takes a singular verb ("has") when referring to zero quantity.', 'Zero out of all.', 'Subject-Verb Agreement'),
(55, 'The movie was ___ boring that we left halfway.', ARRAY['very','so','such','too'], 'so', '''So + adjective + that'' expresses result. "So boring that" shows the consequence.', 'Result clause with adjective.', 'Adjective/Adverb');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(56, 'He was accused ___ stealing the documents.', ARRAY['of','for','with','about'], 'of', '''Accuse of'' is the correct collocation. We accuse someone of doing something.', 'Which preposition follows "accuse"?', 'Preposition'),
(56, 'If you heat water to 100 degrees, it ___.', ARRAY['boils','boiled','will boil','would boil'], 'boils', 'Zero conditional (scientific facts): If + present simple, present simple.', 'A scientific fact.', 'Conditional'),
(56, 'My car ___ serviced at the garage right now.', ARRAY['is','is being','has been','was'], 'is being', 'Present continuous passive: subject + is/are + being + past participle.', 'An action happening right now to the car.', 'Passive Voice'),
(56, 'She said she ___ feeling unwell the previous day.', ARRAY['is','was','has been','had been'], 'had been', 'In reported speech, past continuous shifts to past perfect continuous. "Yesterday" becomes "the previous day".', 'Reported speech with time shift.', 'Reported Speech'),
(56, 'He ___ not swim when he was five, but now he can.', ARRAY['could','can','may','might'], 'could', '''Could'' is the past tense of "can" and is used for past ability.', 'Past ability.', 'Modal Verb');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(57, 'She apologized ___ arriving late to the meeting.', ARRAY['for','of','about','on'], 'for', '''Apologize for'' is the correct collocation.', 'Which preposition follows "apologize"?', 'Preposition'),
(57, '___ Netherlands is a country in Europe.', ARRAY['A','An','The','No article'], 'The', 'We use "The" before country names that are plural or include words like "Kingdom" or "Republic".', 'Plural-form country names.', 'Article'),
(57, 'By next July, they ___ married for twenty years.', ARRAY['will be','are','will have been','have been'], 'will have been', 'Future perfect: will have been, for a state continuing up to a future point.', 'Duration continuing to a future time.', 'Tense'),
(57, 'Ten kilometers ___ a long distance to walk.', ARRAY['is','are','were','have been'], 'is', 'Distances, amounts of money, and periods of time are treated as singular.', 'Is a distance singular or plural?', 'Subject-Verb Agreement'),
(57, 'The girl ___ father is a pilot lives next door.', ARRAY['who','whom','whose','which'], 'whose', '''Whose'' shows possession. The father belongs to the girl.', 'Possessive relative pronoun.', 'Relative Clause');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(58, 'She aimed ___ becoming a doctor.', ARRAY['at','for','to','on'], 'at', '''Aim at'' is the correct collocation when followed by a gerund.', 'Which preposition follows "aim"?', 'Preposition'),
(58, 'If we ___ harder, we would have won the championship.', ARRAY['trained','had trained','have trained','were training'], 'had trained', 'Third conditional if-clause: If + had + past participle for unreal past.', 'Unreal past condition.', 'Conditional'),
(58, 'The bridge ___ over fifty years ago.', ARRAY['built','was built','has been built','is built'], 'was built', 'Past simple passive for a completed action in the past.', 'When was the action completed?', 'Passive Voice'),
(58, 'She told him ___ she had already eaten.', ARRAY['what','if','that','whether'], 'that', '''That'' introduces a reported statement.', 'Reporting a statement.', 'Reported Speech'),
(58, 'Please give ___ the books that are on the table.', ARRAY['I','me','my','mine'], 'me', '''Me'' is the object pronoun. After the verb "give," we need an object pronoun.', 'Subject vs. object pronoun.', 'Pronoun');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(59, 'The company invested heavily ___ new technology.', ARRAY['in','on','for','at'], 'in', '''Invest in'' is the correct collocation.', 'Which preposition follows "invest"?', 'Preposition'),
(59, 'I wish I ___ more time to complete the project.', ARRAY['have','had','has','having'], 'had', '''Wish + past simple'' expresses an unreal present desire.', 'Wishing for something unreal now.', 'Conditional'),
(59, 'The homework ___ be submitted by Friday.', ARRAY['can','may','must','might'], 'must', '''Must'' expresses a strong obligation or requirement.', 'A strong obligation.', 'Modal Verb'),
(59, 'She is ___ intelligent ___ her older sister.', ARRAY['as...as','more...than','so...that','too...to'], 'as...as', '''As...as'' is used for equal comparisons.', 'Comparing two equal things.', 'Adjective/Adverb'),
(59, 'He went to the store ___ he needed to buy groceries.', ARRAY['because','although','so','but'], 'because', '''Because'' introduces a reason or cause.', 'Reason for the action.', 'Conjunction');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(60, 'She is skilled ___ painting landscapes.', ARRAY['at','in','on','for'], 'in', '''Skilled in'' is the correct collocation for areas of expertise.', 'Which preposition follows "skilled"?', 'Preposition'),
(60, '___ Bible is the most widely read book in the world.', ARRAY['A','An','The','No article'], 'The', 'We use "The" before names of holy books.', 'Article for holy books.', 'Article'),
(60, 'She ___ her homework before she went out to play.', ARRAY['finishes','finished','had finished','has finished'], 'had finished', 'Past perfect is used for an action completed before another past action.', 'Which happened first?', 'Tense'),
(60, 'The city ___ I was born is very beautiful.', ARRAY['which','that','where','when'], 'where', '''Where'' is a relative adverb used for places.', 'Referring to a place.', 'Relative Clause'),
(60, '___ you ___ I will attend the ceremony.', ARRAY['Either...or','Neither...nor','Both...and','Not only...but also'], 'Either...or', '''Either...or'' presents two alternatives — one of the two will attend.', 'Choosing between two options.', 'Conjunction');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(61, 'He has been absent ___ school for three days.', ARRAY['from','of','at','in'], 'from', '''Absent from'' is the correct collocation.', 'Which preposition follows "absent"?', 'Preposition'),
(61, 'All the furniture ___ been moved to the new office.', ARRAY['has','have','are','were'], 'has', '''Furniture'' is an uncountable noun and takes a singular verb.', 'Is "furniture" countable?', 'Subject-Verb Agreement'),
(61, 'The witness claimed that she ___ the suspect before.', ARRAY['never sees','never saw','had never seen','has never seen'], 'had never seen', 'Reported speech: past tense shifts to past perfect when the reporting verb is in past.', 'Reported speech tense shift.', 'Reported Speech'),
(61, 'She ___ be at the office by now; she left an hour ago.', ARRAY['must','can','may','shall'], 'must', '''Must'' expresses logical deduction about a present situation.', 'Logical conclusion.', 'Modal Verb'),
(61, 'He is ___ young ___ drive a car legally.', ARRAY['so...that','too...to','as...as','enough...to'], 'too...to', '''Too...to'' means excessively — he is excessively young, so he cannot drive.', 'Excess leading to inability.', 'Adjective/Adverb');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(62, 'The students refrained ___ talking during the exam.', ARRAY['from','of','to','in'], 'from', '''Refrain from'' means to stop oneself from doing something.', 'Which preposition follows "refrain"?', 'Preposition'),
(62, 'If she ___ the truth, he would forgive her.', ARRAY['tells','told','had told','would tell'], 'told', 'Second conditional: If + past simple for an unreal present situation.', 'Hypothetical present.', 'Conditional'),
(62, 'This castle ___ in the 15th century.', ARRAY['was building','was built','has been built','built'], 'was built', 'Past simple passive for a historical fact.', 'Historical action — active or passive?', 'Passive Voice'),
(62, 'The day ___ we met was unforgettable.', ARRAY['which','where','when','that'], 'when', '''When'' is a relative adverb used for time.', 'Referring to a time.', 'Relative Clause'),
(62, 'Neither my brother ___ my sister likes spinach.', ARRAY['or','and','nor','but'], 'nor', '''Neither...nor'' is the correct correlative conjunction pair.', 'What pairs with "neither"?', 'Conjunction');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(63, 'She confided ___ her best friend about the secret.', ARRAY['in','to','with','on'], 'in', '''Confide in'' someone means to share a secret with them.', 'Which preposition follows "confide"?', 'Preposition'),
(63, '___ United States of America has fifty states.', ARRAY['A','An','The','No article'], 'The', 'We use "The" before country names that contain "States," "Republic," or "Kingdom."', 'Country with a descriptive word.', 'Article'),
(63, 'She ___ to Paris three times so far.', ARRAY['went','goes','has been','had been'], 'has been', 'Present perfect with "so far" indicates an experience up to the present.', '"So far" requires which tense?', 'Tense'),
(63, 'The children hurt ___ while playing in the garden.', ARRAY['they','them','their','themselves'], 'themselves', '''Themselves'' is a reflexive pronoun — the children performed and received the action.', 'Same subject and object.', 'Pronoun'),
(63, 'You ___ take an umbrella; it looks like rain.', ARRAY['would','could','had better','might'], 'had better', '''Had better'' gives strong advice, implying negative consequences otherwise.', 'Strong advice.', 'Modal Verb');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(64, 'He has a talent ___ playing the guitar.', ARRAY['for','of','in','at'], 'for', '''Talent for'' is the correct collocation.', 'Which preposition follows "talent"?', 'Preposition'),
(64, 'If you had asked me, I ___ helped you.', ARRAY['will have','would','would have','can'], 'would have', 'Third conditional result clause: would have + past participle.', 'Unreal past result.', 'Conditional'),
(64, 'A lot of research ___ being conducted on this topic.', ARRAY['is','are','were','have'], 'is', '''Research'' is an uncountable noun and takes a singular verb.', 'Is "research" countable?', 'Subject-Verb Agreement'),
(64, 'She asked me ___ I could lend her some money.', ARRAY['that','what','if','which'], 'if', 'Reported yes/no questions use "if" or "whether".', 'Reporting a yes/no question.', 'Reported Speech'),
(64, 'He is old ___ to make his own decisions.', ARRAY['too','very','enough','so'], 'enough', '''Adjective + enough + to'' means sufficiently. He is sufficiently old.', 'Sufficient degree.', 'Adjective/Adverb');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(65, 'The report was prepared ___ the committee members.', ARRAY['from','with','by','to'], 'by', '''By'' is used to indicate the agent in passive voice constructions.', 'Who performed the action?', 'Preposition'),
(65, 'The email ___ to all employees last night.', ARRAY['sent','was sent','is sent','has sent'], 'was sent', 'Past simple passive: was/were + past participle for a completed past action.', 'Passive voice in the past.', 'Passive Voice'),
(65, 'He told me ___ wait for him outside.', ARRAY['that','if','to','whether'], 'to', 'Reported commands: told + object + to-infinitive. No conjunction is needed.', 'Reported command structure.', 'Reported Speech'),
(65, 'This is the restaurant ___ serves the best pasta.', ARRAY['who','whom','which','whose'], 'which', '''Which'' is used for things. The restaurant is a thing, not a person.', 'Person or thing?', 'Relative Clause'),
(65, 'She speaks French ___ she has never lived in France.', ARRAY['so','because','even though','therefore'], 'even though', '''Even though'' introduces a concession — surprising contrast.', 'Contrast or reason?', 'Conjunction');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(66, 'They agreed ___ meet at the coffee shop at noon.', ARRAY['for','on','to','with'], 'to', '''Agree to'' + infinitive means to consent to do something.', 'Which preposition follows "agree" before an infinitive?', 'Preposition'),
(66, '___ Lake Victoria is the largest lake in Africa.', ARRAY['A','An','The','No article'], 'No article', 'No article is used before the names of individual lakes.', 'Article rule for lakes.', 'Article'),
(66, 'She ___ for the company for ten years by next March.', ARRAY['will work','will have worked','works','has worked'], 'will have worked', 'Future perfect: will have + past participle for actions completed by a future point.', 'Duration up to a future point.', 'Tense'),
(66, 'She blamed ___ for the mistake even though it was not her fault.', ARRAY['she','her','hers','herself'], 'herself', '''Herself'' is reflexive — she blamed herself (same person as subject).', 'Subject and object are the same.', 'Pronoun'),
(66, 'You ___ not park here; it is a restricted area.', ARRAY['can','may','must','need'], 'must', '''Must not'' expresses prohibition.', 'Prohibition.', 'Modal Verb');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(67, 'She persisted ___ asking questions until she got an answer.', ARRAY['in','on','with','for'], 'in', '''Persist in'' is the correct collocation meaning to continue doing something.', 'Which preposition follows "persist"?', 'Preposition'),
(67, 'If I had known about the party, I ___ attended.', ARRAY['will have','would have','could','should'], 'would have', 'Third conditional: would have + past participle for an unreal past result.', 'Regret about a past missed event.', 'Conditional'),
(67, 'The suspect ___ by the police at dawn.', ARRAY['arrested','was arrested','has arrested','is arresting'], 'was arrested', 'Past simple passive: was + past participle.', 'Past event, focus on the suspect.', 'Passive Voice'),
(67, 'She said, "I am leaving." She said that she ___ leaving.', ARRAY['is','was','has been','had been'], 'was', 'Reported speech: "am" shifts to "was" when the reporting verb is past.', 'Direct to indirect speech.', 'Reported Speech'),
(67, 'This is ___ interesting book I have ever read.', ARRAY['a most','the more','the most','a more'], 'the most', 'Superlative with "the most" + adjective for multi-syllable words like "interesting".', 'Superlative form.', 'Adjective/Adverb');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(68, 'He is anxious ___ the results of the examination.', ARRAY['about','for','of','with'], 'about', '''Anxious about'' means worried about something.', 'Which preposition follows "anxious"?', 'Preposition'),
(68, '___ Philippines is an archipelago in Southeast Asia.', ARRAY['A','An','The','No article'], 'The', 'We use "The" before country names that are plural.', 'Plural country name.', 'Article'),
(68, 'They ___ each other since they were in kindergarten.', ARRAY['know','knew','have known','had known'], 'have known', 'Present perfect with "since" for an ongoing state from a past point.', '"Since" with present perfect.', 'Tense'),
(68, 'The man ___ car was stolen reported it to the police.', ARRAY['who','whom','whose','which'], 'whose', '''Whose'' indicates possession. The car belongs to the man.', 'Possessive relative pronoun.', 'Relative Clause'),
(68, 'He studied hard, ___ he failed the exam.', ARRAY['so','but','and','or'], 'but', '''But'' introduces a contrast between studying hard and failing.', 'Contrast between two clauses.', 'Conjunction');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(69, 'She has a preference ___ classical music.', ARRAY['for','of','to','in'], 'for', '''Preference for'' is the correct collocation.', 'Which preposition follows "preference"?', 'Preposition'),
(69, 'Unless you hurry, you ___ miss the bus.', ARRAY['would','will','can','might'], 'will', '''Unless'' introduces a negative condition. First conditional: unless + present, will + base verb.', 'Negative condition with real consequence.', 'Conditional'),
(69, 'These shirts ___ in Bangladesh.', ARRAY['made','are made','have made','making'], 'are made', 'Present simple passive: are + past participle for general facts.', 'Where are they manufactured?', 'Passive Voice'),
(69, 'Each of the boys ___ given a certificate.', ARRAY['was','were','are','have been'], 'was', '''Each of'' takes a singular verb.', '"Each of" — singular or plural verb?', 'Subject-Verb Agreement'),
(69, '___ she nor her parents attended the function.', ARRAY['Either','Neither','Both','Not only'], 'Neither', '''Neither...nor'' is the correct pair. "Neither she nor her parents" negates both.', 'Double negation.', 'Conjunction');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(70, 'He reminds me ___ my grandfather.', ARRAY['of','about','for','to'], 'of', '''Remind someone of'' means to cause someone to think of.', 'Which preposition follows "remind...of"?', 'Preposition'),
(70, 'She wanted to know what time the train ___.', ARRAY['leaves','left','has left','had left'], 'left', 'Reported speech: present simple shifts to past simple.', 'Tense shift in reported speech.', 'Reported Speech'),
(70, 'I ___ rather stay home than go to the party.', ARRAY['will','would','should','could'], 'would', '''Would rather'' expresses preference.', 'Expressing a preference.', 'Modal Verb'),
(70, 'She is not ___ tall ___ her mother.', ARRAY['as...as','so...that','too...to','more...than'], 'as...as', '''Not as...as'' expresses inequality in comparison.', 'Negative comparison.', 'Adjective/Adverb'),
(70, 'Let each person do ___ best in the competition.', ARRAY['his','their','its','one''s'], 'their', '''Their'' is used as a gender-neutral singular pronoun with "each person".', 'Gender-neutral reference.', 'Pronoun');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(71, 'She opted ___ the cheaper alternative.', ARRAY['for','to','of','with'], 'for', '''Opt for'' means to choose something.', 'Which preposition follows "opt"?', 'Preposition'),
(71, 'If water reaches zero degrees, it ___.', ARRAY['freezes','froze','will freeze','would freeze'], 'freezes', 'Zero conditional for scientific facts: If + present, present.', 'A fact about water.', 'Conditional'),
(71, 'The new shopping mall ___ inaugurated by the mayor next week.', ARRAY['is','will be','was','has been'], 'will be', 'Future simple passive: will be + past participle.', 'A future event in passive.', 'Passive Voice'),
(71, 'A large number of employees ___ dissatisfied with the new policy.', ARRAY['is','are','was','has'], 'are', '''A number of'' takes a plural verb because it means "many".', '"A number of" — singular or plural?', 'Subject-Verb Agreement'),
(71, 'The scientist ___ discovered penicillin won the Nobel Prize.', ARRAY['who','whom','whose','which'], 'who', '''Who'' is the subject relative pronoun for people.', 'The scientist performed the action.', 'Relative Clause');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(72, 'She is dedicated ___ helping the underprivileged.', ARRAY['to','for','in','on'], 'to', '''Dedicated to'' is the correct collocation.', 'Which preposition follows "dedicated"?', 'Preposition'),
(72, '___ Indian Ocean is the third largest ocean.', ARRAY['A','An','The','No article'], 'The', 'We use "The" before names of oceans.', 'Article rule for oceans.', 'Article'),
(72, 'We ___ dinner when the doorbell rang.', ARRAY['had','were having','have had','are having'], 'were having', 'Past continuous for an action in progress interrupted by a past event.', 'Interrupted action in the past.', 'Tense'),
(72, 'He asked me ___ I wanted tea or coffee.', ARRAY['that','if','whether','what'], 'whether', '''Whether'' is used when there are two specific alternatives (tea or coffee).', 'Choice between two options.', 'Reported Speech'),
(72, 'She speaks English ___ than most of her classmates.', ARRAY['more fluently','most fluently','fluently','very fluently'], 'more fluently', 'Comparative adverb with "than": more + adverb + than.', 'Comparing two groups.', 'Adjective/Adverb');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(73, 'The project was entrusted ___ the senior engineer.', ARRAY['to','with','for','on'], 'to', '''Entrust to'' someone means to give responsibility to that person.', 'Who receives the responsibility?', 'Preposition'),
(73, 'If I ___ a bird, I would fly around the world.', ARRAY['am','was','were','be'], 'were', 'Second conditional (unreal present): "were" is used for hypothetical situations.', 'An impossible wish.', 'Conditional'),
(73, 'The window ___ broken by the children playing cricket.', ARRAY['has','was','is','had'], 'was', 'Past simple passive: was + past participle for a completed past event.', 'A past event — who broke it?', 'Passive Voice'),
(73, 'Someone left ___ jacket in the classroom.', ARRAY['his','her','its','their'], 'their', '''Their'' is the gender-neutral possessive pronoun for an unknown person.', 'Unknown gender.', 'Pronoun'),
(73, 'She ___ speak three languages by the time she was twelve.', ARRAY['can','could','may','might'], 'could', '''Could'' expresses past ability.', 'Ability in the past.', 'Modal Verb');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(74, 'They have been quarreling ___ each other all day.', ARRAY['with','to','at','for'], 'with', '''Quarrel with'' is the correct collocation.', 'Which preposition follows "quarrel"?', 'Preposition'),
(74, '___ Mona Lisa is displayed in the Louvre Museum.', ARRAY['A','An','The','No article'], 'The', 'We use "The" before names of famous works of art.', 'Famous artwork.', 'Article'),
(74, 'She ___ to the gym regularly before she injured her knee.', ARRAY['goes','went','used to go','has gone'], 'used to go', '''Used to'' describes a past habit that no longer continues.', 'A past habit.', 'Tense'),
(74, 'The teacher ___ class I enjoy the most is Mrs. Williams.', ARRAY['who','whom','whose','which'], 'whose', '''Whose'' shows possession. The class belongs to the teacher.', 'Possessive in a relative clause.', 'Relative Clause'),
(74, 'He ran fast ___ he could catch the last train.', ARRAY['so that','because','although','unless'], 'so that', '''So that'' expresses purpose.', 'Purpose of running fast.', 'Conjunction');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(75, 'She prevailed ___ her opponents in the debate.', ARRAY['over','on','at','with'], 'over', '''Prevail over'' means to triumph against.', 'Which preposition follows "prevail"?', 'Preposition'),
(75, 'I wish I ___ studied medicine instead of law.', ARRAY['have','has','had','would'], 'had', '''Wish + past perfect'' expresses regret about a past action.', 'Regretting a past decision.', 'Conditional'),
(75, 'The package ___ delivered to your doorstep tomorrow.', ARRAY['is','will be','was','has been'], 'will be', 'Future simple passive: will be + past participle.', 'A future event.', 'Passive Voice'),
(75, 'The doctor advised him ___ smoking immediately.', ARRAY['stop','to stop','stopping','stopped'], 'to stop', '''Advise someone to do something'' uses the to-infinitive pattern.', 'Reported advice pattern.', 'Reported Speech'),
(75, 'She plays the violin ___ beautifully than anyone else in the orchestra.', ARRAY['most','more','very','much'], 'more', 'Comparative adverb: more + adverb + than.', 'Comparing with "than".', 'Adjective/Adverb');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(76, 'He derives great pleasure ___ reading books.', ARRAY['from','of','in','by'], 'from', '''Derive from'' is the correct collocation.', 'Which preposition follows "derive"?', 'Preposition'),
(76, '___ news about the merger has surprised everyone.', ARRAY['A','An','The','No article'], 'The', 'We use "The" for specific news already known to the listener.', 'Specific or general news?', 'Article'),
(76, 'By this time next year, I ___ my master''s degree.', ARRAY['complete','completed','will have completed','have completed'], 'will have completed', 'Future perfect: will have + past participle for a future action completed by a specific time.', 'Completed before a future point.', 'Tense'),
(76, 'Physics ___ my favorite subject at school.', ARRAY['is','are','were','have been'], 'is', 'Subject names ending in -s (physics, mathematics) are singular.', 'Subjects ending in -s.', 'Subject-Verb Agreement'),
(76, 'You ___ consult a lawyer before signing that contract.', ARRAY['would','shall','ought to','might'], 'ought to', '''Ought to'' expresses a moral obligation or strong recommendation.', 'Strong recommendation.', 'Modal Verb');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(77, 'She warned him ___ the dangerous path ahead.', ARRAY['about','of','for','on'], 'about', '''Warn someone about'' something means to alert them.', 'Which preposition follows "warn...about"?', 'Preposition'),
(77, 'If he ___ the instructions carefully, he would not have made mistakes.', ARRAY['reads','read','had read','has read'], 'had read', 'Third conditional: If + had + past participle for an unreal past.', 'Past action that did not happen.', 'Conditional'),
(77, 'The museum ___ visited by thousands of tourists every year.', ARRAY['is','was','has','had'], 'is', 'Present simple passive for habitual or regular actions.', 'A regular occurrence.', 'Passive Voice'),
(77, 'This is the school ___ I studied for twelve years.', ARRAY['which','that','where','when'], 'where', '''Where'' is a relative adverb for places.', 'Referring to a place.', 'Relative Clause'),
(77, 'She bought a dress ___ a matching handbag.', ARRAY['but','or','and','yet'], 'and', '''And'' connects two items purchased together.', 'Adding items together.', 'Conjunction');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(78, 'The committee consists ___ twelve members.', ARRAY['of','in','with','from'], 'of', '''Consist of'' means to be made up of.', 'Which preposition follows "consist"?', 'Preposition'),
(78, '___ European country I would most like to visit is Italy.', ARRAY['A','An','The','No article'], 'The', 'We use "The" when specifying a particular noun with a superlative or defining phrase.', 'Specific reference.', 'Article'),
(78, 'He ___ for the company for five years before he was promoted.', ARRAY['works','worked','had worked','has worked'], 'had worked', 'Past perfect for an action completed before another past event (his promotion).', 'Which happened first?', 'Tense'),
(78, 'The journalist asked the minister ___ he planned to resign.', ARRAY['that','what','whether','which'], 'whether', '''Whether'' introduces a reported yes/no question.', 'Reporting a yes/no question.', 'Reported Speech'),
(78, 'She is ___ the tallest girl in our class.', ARRAY['very','much','by far','more'], 'by far', '''By far'' is used to emphasize a superlative.', 'Emphasizing a superlative.', 'Adjective/Adverb');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(79, 'He was charged ___ a serious criminal offense.', ARRAY['with','for','of','by'], 'with', '''Charged with'' is the correct legal collocation.', 'Legal terminology: which preposition?', 'Preposition'),
(79, 'If you mix blue and yellow, you ___ green.', ARRAY['get','got','will get','would get'], 'get', 'Zero conditional for a general truth: If + present, present.', 'A general truth about colors.', 'Conditional'),
(79, 'These questions ___ answered before the deadline.', ARRAY['must be','must','are must','must being'], 'must be', 'Passive with modal: must + be + past participle.', 'Modal + passive.', 'Passive Voice'),
(79, 'Neither the manager ___ the assistants knew about the schedule change.', ARRAY['or','nor','and','but'], 'nor', '''Neither...nor'' connects two negated items.', 'What pairs with "neither"?', 'Conjunction'),
(79, 'She introduced ___ to the new colleagues at the meeting.', ARRAY['she','her','hers','herself'], 'herself', '''Herself'' is reflexive — she introduced herself.', 'Subject and object are the same person.', 'Pronoun');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(80, 'We must comply ___ the new regulations.', ARRAY['with','to','by','for'], 'with', '''Comply with'' means to follow rules or regulations.', 'Which preposition follows "comply"?', 'Preposition'),
(80, '___ Nile is the longest river in Africa.', ARRAY['A','An','The','No article'], 'The', 'We use "The" before names of rivers.', 'Article for rivers.', 'Article'),
(80, 'She ___ the piano since she was six years old.', ARRAY['plays','played','has been playing','is playing'], 'has been playing', 'Present perfect continuous for an action that started in the past and continues now.', 'Action from past to present.', 'Tense'),
(80, 'The crowd ___ cheering loudly when the team scored.', ARRAY['is','was','are','were'], 'was', '''Crowd'' is a collective noun treated as singular when acting as one unit.', 'Collective noun — singular or plural?', 'Subject-Verb Agreement'),
(80, 'He ___ have eaten the cake; the box is empty.', ARRAY['can','must','should','would'], 'must', '''Must have + past participle'' expresses a strong logical deduction about the past.', 'Logical deduction about the past.', 'Modal Verb');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(81, 'She took advantage ___ the opportunity.', ARRAY['of','from','on','in'], 'of', '''Take advantage of'' is the correct collocation.', 'Which preposition follows "take advantage"?', 'Preposition'),
(81, 'If only she ___ accepted the offer when she had the chance.', ARRAY['has','have','had','would'], 'had', '''If only + past perfect'' expresses regret about a past action.', 'Regret about the past.', 'Conditional'),
(81, 'The new policy ___ implemented starting next month.', ARRAY['will be','is','was','has been'], 'will be', 'Future simple passive: will be + past participle.', 'A future implementation.', 'Passive Voice'),
(81, 'The teacher reminded the students ___ they should bring their textbooks.', ARRAY['if','whether','what','that'], 'that', '''That'' introduces a reported statement.', 'Reporting a statement.', 'Reported Speech'),
(81, 'She is the woman ___ I was telling you about.', ARRAY['who','whom','whose','which'], 'whom', '''Whom'' is used as the object of the preposition "about" in the relative clause.', 'Object of a preposition.', 'Relative Clause');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(82, 'He is not satisfied ___ the quality of the product.', ARRAY['with','of','for','by'], 'with', '''Satisfied with'' is the correct collocation.', 'Which preposition follows "satisfied"?', 'Preposition'),
(82, 'She can dance ___ gracefully ___ a professional ballerina.', ARRAY['as...as','so...that','more...than','too...to'], 'as...as', '''As...as'' for equal comparisons.', 'Equal comparison.', 'Adjective/Adverb'),
(82, 'The two brothers look exactly like ___.', ARRAY['each one','one another','each other','themselves'], 'each other', '''Each other'' is used when two people perform the same action reciprocally.', 'Reciprocal action between two.', 'Pronoun'),
(82, 'Bread and butter ___ his usual breakfast.', ARRAY['is','are','were','have been'], 'is', 'When two nouns joined by "and" refer to a single item or concept, the verb is singular.', 'Single concept or two items?', 'Subject-Verb Agreement'),
(82, 'She likes coffee ___ her sister prefers tea.', ARRAY['but','and','so','or'], 'but', '''But'' introduces a contrast between the two preferences.', 'Contrast.', 'Conjunction');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(83, 'He was acquitted ___ all charges by the court.', ARRAY['of','from','with','for'], 'of', '''Acquit of'' is the correct legal collocation.', 'Legal term: which preposition?', 'Preposition'),
(83, 'I would travel more if I ___ more vacation days.', ARRAY['have','has','had','having'], 'had', 'Second conditional: If + past simple for an unreal present situation.', 'Hypothetical present.', 'Conditional'),
(83, 'All the arrangements ___ been made for the conference.', ARRAY['has','have','is','was'], 'have', '''Arrangements'' is plural and takes "have".', 'Plural noun.', 'Subject-Verb Agreement'),
(83, 'He told her not ___ worry about the results.', ARRAY['for','that','to','if'], 'to', 'Reported negative command: told + object + not + to-infinitive.', 'Reported negative command.', 'Reported Speech'),
(83, 'The house ___ we grew up in has been demolished.', ARRAY['who','whom','which','whose'], 'which', '''Which'' is used for things. A house is a thing.', 'Referring to a thing.', 'Relative Clause');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(84, 'She contributed generously ___ the charity fund.', ARRAY['to','for','in','at'], 'to', '''Contribute to'' is the correct collocation.', 'Which preposition follows "contribute"?', 'Preposition'),
(84, '___ Alps are a famous mountain range in Europe.', ARRAY['A','An','The','No article'], 'The', 'We use "The" before names of mountain ranges.', 'Article for mountain ranges.', 'Article'),
(84, 'He ___ in London before he moved to New York in 2020.', ARRAY['lives','lived','had lived','has lived'], 'had lived', 'Past perfect for an action completed before another past action.', 'Sequence of past events.', 'Tense'),
(84, 'You ___ not touch the exhibits in the museum.', ARRAY['can','must','shall','would'], 'must', '''Must not'' expresses a prohibition or strict rule.', 'A strict rule.', 'Modal Verb'),
(84, 'She finished the race ___ being exhausted.', ARRAY['although','despite','because','so'], 'despite', '''Despite'' + gerund expresses contrast.', 'Contrast with a gerund.', 'Conjunction');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(85, 'The plan hinges ___ the approval of the board.', ARRAY['on','at','in','for'], 'on', '''Hinge on'' means to depend on.', 'Which preposition follows "hinge"?', 'Preposition'),
(85, 'If she were taller, she ___ a basketball player.', ARRAY['will be','would be','is','was'], 'would be', 'Second conditional result: would + base verb.', 'Hypothetical present result.', 'Conditional'),
(85, 'Several houses ___ damaged in the earthquake last night.', ARRAY['are','were','have','had'], 'were', 'Past simple passive (the full form is "were damaged").', 'Past event in passive.', 'Passive Voice'),
(85, 'He suggested ___ we take a different route.', ARRAY['if','whether','what','that'], 'that', '''Suggest that'' introduces a reported suggestion.', 'Reporting a suggestion.', 'Reported Speech'),
(85, 'This painting is ___ expensive than the one we saw yesterday.', ARRAY['most','very','more','much'], 'more', 'Comparative with multi-syllable adjectives: more + adjective + than.', 'Comparative form.', 'Adjective/Adverb');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(86, 'She is envious ___ her colleague''s promotion.', ARRAY['of','for','about','with'], 'of', '''Envious of'' is the correct collocation.', 'Which preposition follows "envious"?', 'Preposition'),
(86, '___ Great Wall of China is visible from space.', ARRAY['A','An','The','No article'], 'The', 'We use "The" before specific famous landmarks and structures.', 'Famous structure.', 'Article'),
(86, 'She ___ at this school for fifteen years by next September.', ARRAY['teaches','will teach','will have been teaching','has been teaching'], 'will have been teaching', 'Future perfect continuous for an ongoing action up to a future point.', 'Duration up to a future point.', 'Tense'),
(86, 'Somebody has left ___ bag on the train.', ARRAY['his','her','its','their'], 'their', '''Their'' is used as a gender-neutral singular possessive for "somebody".', 'Unknown gender.', 'Pronoun'),
(86, 'The project ___ be completed by the end of this quarter.', ARRAY['would','shall','can','should'], 'should', '''Should'' expresses expectation or obligation.', 'Expected outcome.', 'Modal Verb');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(87, 'She is intent ___ finishing the course before summer.', ARRAY['on','in','at','for'], 'on', '''Intent on'' means determined to do something.', 'Which preposition follows "intent"?', 'Preposition'),
(87, 'If I had not missed the alarm, I ___ late for work.', ARRAY['would not be','would not have been','will not be','am not'], 'would not have been', 'Third conditional (unreal past): would not have + past participle.', 'An unreal past result.', 'Conditional'),
(87, 'The flowers ___ watered every morning by the gardener.', ARRAY['is','are','was','were'], 'are', 'Present simple passive: are + past participle for routine actions.', 'Routine action in passive.', 'Passive Voice'),
(87, 'The professor ___ lectures are always engaging has won an award.', ARRAY['who','whom','whose','which'], 'whose', '''Whose'' shows possession. The lectures belong to the professor.', 'Possessive relative pronoun.', 'Relative Clause'),
(87, 'She speaks softly ___ she does not want to wake the baby.', ARRAY['because','although','so','but'], 'because', '''Because'' gives the reason for speaking softly.', 'Reason.', 'Conjunction');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(88, 'He boasted ___ his achievements at the meeting.', ARRAY['about','of','for','on'], 'about', '''Boast about'' means to talk proudly about something.', 'Which preposition follows "boast"?', 'Preposition'),
(88, 'If you practice every day, you ___ improve quickly.', ARRAY['would','will','could','might'], 'will', 'First conditional (real possibility): If + present, will + base verb.', 'A real condition.', 'Conditional'),
(88, 'The number of students enrolled this year ___ increased significantly.', ARRAY['has','have','are','were'], 'has', '''The number of'' takes a singular verb.', '"The number of" — singular or plural?', 'Subject-Verb Agreement'),
(88, 'She exclaimed that the scenery ___ breathtaking.', ARRAY['is','was','has been','were'], 'was', 'Reported speech: "is" shifts to "was" when the reporting verb is past.', 'Tense shift in reported speech.', 'Reported Speech'),
(88, 'He was ___ exhausted to continue the hike.', ARRAY['very','so','too','enough'], 'too', '''Too + adjective + to'' means excessively, resulting in inability.', 'Excessive degree.', 'Adjective/Adverb');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(89, 'The professor dwelt ___ the importance of critical thinking.', ARRAY['on','in','at','for'], 'on', '''Dwell on'' means to think or talk about something at length.', 'Which preposition follows "dwell"?', 'Preposition'),
(89, '___ Sahara Desert is the largest hot desert in the world.', ARRAY['A','An','The','No article'], 'The', 'We use "The" before names of deserts.', 'Article for deserts.', 'Article'),
(89, 'She ___ in the garden when it started to rain.', ARRAY['works','worked','was working','has worked'], 'was working', 'Past continuous for an ongoing action interrupted by another event.', 'Ongoing action interrupted.', 'Tense'),
(89, 'The office ___ she works is on the fifth floor.', ARRAY['which','that','where','when'], 'where', '''Where'' is a relative adverb for places.', 'Referring to a place.', 'Relative Clause'),
(89, 'He ___ have left his keys at the restaurant; let me call them.', ARRAY['must','can','should','will'], 'must', '''Must have + past participle'' for strong logical deduction about the past.', 'Logical deduction.', 'Modal Verb');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(90, 'She clings ___ the hope of being reunited with her family.', ARRAY['to','on','at','for'], 'to', '''Cling to'' means to hold tightly or be emotionally attached.', 'Which preposition follows "cling"?', 'Preposition'),
(90, 'If I ___ the lottery, I would donate half to charity.', ARRAY['win','won','had won','will win'], 'won', 'Second conditional: If + past simple for an unreal present.', 'Hypothetical situation.', 'Conditional'),
(90, 'The report ___ already ___ submitted to the director.', ARRAY['has...been','have...been','is...being','was...being'], 'has...been', 'Present perfect passive: has/have + been + past participle.', 'Completed action with present relevance.', 'Passive Voice'),
(90, 'He asked her ___ she had enjoyed the concert.', ARRAY['that','what','if','which'], 'if', 'Reported yes/no question: use "if" or "whether".', 'Reporting a yes/no question.', 'Reported Speech'),
(90, 'She is ___ talented ___ she can play five instruments.', ARRAY['so...that','such...that','as...as','too...to'], 'so...that', '''So + adjective + that'' shows cause and effect.', 'Cause and effect.', 'Adjective/Adverb');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(91, 'He was overwhelmed ___ the response to his speech.', ARRAY['by','with','of','from'], 'by', '''Overwhelmed by'' is the correct collocation for reactions.', 'Which preposition follows "overwhelmed"?', 'Preposition'),
(91, '___ Pacific Ocean is the deepest ocean in the world.', ARRAY['A','An','The','No article'], 'The', 'We use "The" before names of oceans.', 'Article for oceans.', 'Article'),
(91, 'They ___ their old house and bought a new one last year.', ARRAY['sell','sold','have sold','had sold'], 'sold', 'Past simple for a completed action with a specific past time marker ("last year").', 'Specific past time.', 'Tense'),
(91, 'Fifty dollars ___ a lot of money for a child.', ARRAY['is','are','were','have been'], 'is', 'Amounts of money are treated as singular.', 'Money amount — singular or plural?', 'Subject-Verb Agreement'),
(91, 'You ___ to see a dentist about that toothache.', ARRAY['would','shall','need','might'], 'need', '''Need to'' expresses necessity.', 'Expressing necessity.', 'Modal Verb');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(92, 'She yearns ___ a peaceful life in the countryside.', ARRAY['for','of','to','about'], 'for', '''Yearn for'' means to desire deeply.', 'Which preposition follows "yearn"?', 'Preposition'),
(92, 'If they ___ more carefully, the accident would not have happened.', ARRAY['drive','drove','had driven','have driven'], 'had driven', 'Third conditional: If + had + past participle for an unreal past.', 'Could the accident have been avoided?', 'Conditional'),
(92, 'The medicine ___ be taken twice a day after meals.', ARRAY['must','can','may','shall'], 'must', '''Must'' for medical instructions or strong obligation.', 'Medical instruction.', 'Modal Verb'),
(92, 'She invited all her friends, ___ of whom could attend.', ARRAY['some','any','few','many'], 'few', '''Few of whom'' means not many. It is a non-restrictive relative clause.', 'Relative clause with quantifier.', 'Relative Clause'),
(92, 'He enjoyed the book ___ found the ending disappointing.', ARRAY['and','but','so','or'], 'but', '''But'' introduces a contrast between enjoying the book and finding the ending disappointing.', 'Contrast.', 'Conjunction');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(93, 'The witness testified ___ the defendant''s innocence.', ARRAY['to','for','of','about'], 'to', '''Testify to'' means to serve as evidence of.', 'Which preposition follows "testify"?', 'Preposition'),
(93, '___ Suez Canal connects the Mediterranean and Red Seas.', ARRAY['A','An','The','No article'], 'The', 'We use "The" before names of canals.', 'Article for canals.', 'Article'),
(93, 'She ___ just ___ asleep when the alarm went off.', ARRAY['has...fallen','had...fallen','was...falling','is...falling'], 'had...fallen', 'Past perfect for an action completed just before another past action.', 'Sequence of past events.', 'Tense'),
(93, 'The children were told ___ they could go outside after lunch.', ARRAY['if','whether','what','that'], 'that', '''That'' introduces a reported statement.', 'Reported statement.', 'Reported Speech'),
(93, 'She is ___ intelligent a student that all the teachers praise her.', ARRAY['so','such','very','too'], 'so', '''So + adjective + a/an + noun + that'' is the correct pattern.', 'Cause and effect with noun.', 'Adjective/Adverb');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(94, 'He tampered ___ the evidence and was arrested.', ARRAY['with','of','in','at'], 'with', '''Tamper with'' means to interfere with or alter dishonestly.', 'Which preposition follows "tamper"?', 'Preposition'),
(94, 'If she arrives on time, we ___ start the meeting immediately.', ARRAY['would','will','could','should'], 'will', 'First conditional: If + present, will + base verb.', 'Real condition.', 'Conditional'),
(94, 'All the tickets ___ sold out within an hour.', ARRAY['was','were','is','has'], 'were', 'Past simple passive: were + past participle (tickets is plural).', 'Plural subject in past passive.', 'Passive Voice'),
(94, 'Everyone should do ___ duty sincerely.', ARRAY['his','her','its','their'], 'their', '''Their'' is the gender-neutral possessive for "everyone".', 'Gender-neutral reference.', 'Pronoun'),
(94, 'He is the author ___ latest novel has become a bestseller.', ARRAY['who','whom','whose','which'], 'whose', '''Whose'' shows possession. The novel belongs to the author.', 'Possessive relative pronoun.', 'Relative Clause');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(95, 'She grappled ___ the complex problem for hours.', ARRAY['with','on','at','for'], 'with', '''Grapple with'' means to struggle with a difficult issue.', 'Which preposition follows "grapple"?', 'Preposition'),
(95, 'I would not have been late if the traffic ___ so bad.', ARRAY['is not','was not','had not been','has not been'], 'had not been', 'Third conditional: If + had not + past participle for an unreal past condition.', 'Unreal past condition.', 'Conditional'),
(95, 'The contract ___ signed by both parties yesterday.', ARRAY['is','was','has','had'], 'was', 'Past simple passive: was + past participle for a past event.', 'Past event in passive.', 'Passive Voice'),
(95, 'Three hours ___ a long time to wait for a bus.', ARRAY['is','are','were','have been'], 'is', 'Time periods are treated as singular when considered as a unit.', 'Time as a unit — singular or plural?', 'Subject-Verb Agreement'),
(95, 'She ___ have called before coming; I was not prepared.', ARRAY['would','could','should','might'], 'should', '''Should have + past participle'' expresses criticism about a past action.', 'Criticism about the past.', 'Modal Verb');
INSERT INTO english_questions (day_set, question, options, answer, explanation, hint, category)
VALUES
(96, 'He was sentenced ___ ten years in prison.', ARRAY['to','for','with','of'], 'to', '''Sentenced to'' is the correct legal collocation.', 'Legal term: which preposition?', 'Preposition'),
(96, '___ Bahamas is a popular tourist destination.', ARRAY['A','An','The','No article'], 'The', 'We use "The" before country names that are plural (The Bahamas).', 'Plural country name.', 'Article'),
(96, 'She ___ for two hours before the doctor finally saw her.', ARRAY['waits','waited','had been waiting','has been waiting'], 'had been waiting', 'Past perfect continuous for an action in progress before another past event.', 'Duration before a past event.', 'Tense'),
(96, 'He denied ___ he had taken the money.', ARRAY['if','whether','what','that'], 'that', '''Deny that'' introduces a reported denial.', 'Reporting a denial.', 'Reported Speech'),
(96, 'She not only sings ___ also dances at every performance.', ARRAY['and','or','but','nor'], 'but', '''Not only...but also'' is the correct correlative conjunction pair.', 'What pairs with "not only"?', 'Conjunction');
